-- Migration to fix existing books where availableCopies should = totalCopies\n-- Run this ONCE on booknest database\n\nUPDATE books SET availableCopies = totalCopies WHERE availableCopies < totalCopies OR availableCopies = 0;\n\n-- Verify\nSELECT title, totalCopies, availableCopies FROM books LIMIT 10;\n\n-- Safety check\nSELECT COUNT(*) FROM books WHERE availableCopies > totalCopies OR availableCopies < 0;
